/**
 * 조회 및 마감확인시 작업코드 날짜 세팅하는 함수
 */
scwin.f_setWrkNoFromDate = async function () {
  if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "1") {
    scwin.wrkNo = ACConstants.CLOSE_PLAN_DISTRIBUTION_1;
    scwin.fromDate = ica_fromDate.getValue().trim() + "00";
  } else if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "2") {
    scwin.wrkNo = ACConstants.CLOSE_PLAN_DISTRIBUTION_2;
    scwin.fromDate = ica_fromDate.getValue().trim() + "00";
  } else if (rd_distClsCd.getValue() == "1" && lc_distDegCd.getValue() == "3") {
    scwin.wrkNo = ACConstants.CLOSE_PLAN_DISTRIBUTION_3;
    scwin.fromDate = ica_fromDate.getValue().trim() + "00";
  } else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "1") {
    scwin.wrkNo = ACConstants.CLOSE_RESULTS_DISTRIBUTION_1;
    scwin.fromDate = ica_fromDate.getValue().trim();
  } else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "2") {
    scwin.wrkNo = ACConstants.CLOSE_RESULTS_DISTRIBUTION_2;
    scwin.fromDate = ica_fromDate.getValue().trim();
  } else if (rd_distClsCd.getValue() == "2" && lc_distDegCd.getValue() == "3") {
    scwin.wrkNo = ACConstants.CLOSE_RESULTS_DISTRIBUTION_3;
    scwin.fromDate = ica_fromDate.getValue().trim();
  } else {
    await $c.win.alert($p, "잘못된 조회 조건을 선택하셨습니다. 조회 조건을 확인하시기 바랍니다.");
    return false;
  }
  return true;
};

/**
 * 마감년월 포커스 잃었을 시
 */
scwin.ica_fromDate_onblur = function (e) {
  scwin.f_LoadVer();
};

/**
 * 저장버튼
 */
scwin.f_Save = async function () {
  let msg = ""; // 메세지 저장

  let ret = await $c.gus.cfValidate($p, [ica_fromDate, lc_version, lc_distDegCd, rd_distClsCd, ed_coCd]);
  if (!ret) {
    return false;
  }

  // 마감여부 확인(2006.05.03) 마감여부를 체크 하지 않음 주석처리 되어 있음.
  // wrkNo(마감구분코드)fromDate(년월)의 값을 세팅하기 위해서 호출은 해야함.
  ret = await scwin.f_JobCloseYN();
  if (!ret) {
    return false;
  }
  // 배부처리 실행여부 확인
  await scwin.f_distCount();
  if (Number(ds_tempCount.getCellData(0, "col1")) > 0) {
    msg = "해당 조건의 배부처리를 실행하신적이 있습니다.<BR>배부처리를 재 실행 하시겠습니까?";
  } else {
    msg = "배부처리 Batch Job을 실행하시겠습니까?";
  }
  if ($c.gus.cfIsNull($p, lc_distDegCd.getValue())) {
    await $c.win.alert($p, "실행시는 전체 조건을 선택하실수 없습니다.");
    lc_distDegCd.focus();
    return;
  }
  if (await $c.win.confirm($p, msg)) {
    sbm_save.userData1 = "noError";
    $c.sbm.execute($p, sbm_save);
  }
};
scwin.sbm_save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    await $c.gus.cfAlertMsg($p, e.responseJSON.resultDataSet[1].Msg);
    return;
  }
  if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
    await $c.gus.cfAlertMsg($p, "배부처리 Batch Job이 정상적으로 실행되었습니다.");
    scwin.f_Retrieve();
  }
};

